    /**
     * Fonction : MAJConj
     * Algorithme : 
     *  
    */    
    @Override
    public void MAJConj(Conjugueur.C.Conjug contrôleur)   {
       if (DEBUG) { System.out.println ("Conjugueur.M.ConjTableSyri::MAJConj, Verbe = "+ contrôleur.model.getIndVerbe()+", contrôleur.model.getTemps() = "+Conjugueur.M.ConjugSyri.T.i2T(contrôleur.model.getTemps()).toString()+", Schème = " + contrôleur.model.getSchème()) ; }
        this.contrôleur = contrôleur ; 
        vider();
        déclinaisonChildren = Conjugueur.M.ConjugSyri.comboBoxVerbeM.get(contrôleur.model.getIndVerbe()).getChildren("déclinaison");
        for (char c : Conjugueur.M.ConjugSyri.comboBoxVerbeM.get(contrôleur.model.getIndVerbe()).getAttributeValue(Conjugueur.M.ConjugSyri.ATTRIBUT).toCharArray()){;
            if (Consonne(c)) {                                // le caractère courant est une consonne
                if (nbcons == 0) Pé = c ;
                if (nbcons == 2) Lomad = c ;
                nbcons++ ;
            }                                                 // le caractère courant était une consonne
        }                                                    // pour ts les caractères de la racine
        if(Character.compare('ܐ', Lomad) == 0) ConjClasseSyriM.setClasse( ConjClasseSyriM.SYC.lōmadh_yud) ;
        else  if(Character.compare('ܐ', Pé) == 0) ConjClasseSyriM.setClasse( ConjClasseSyriM.SYC.P_ōlaf)   ;
        else ConjClasseSyriM.setClasse( ConjClasseSyriM.SYC.Fort );
        if (DEBUG) System.out.println ("Conjugueur.M.ConjTableSyri::MAJConj, contrôleur.model.getIndVerbe() = "+Conjugueur.M.ConjugSyri.comboBoxVerbeM.get(contrôleur.model.getIndVerbe()).getAttributeValue(Conjugueur.M.ConjugSyri.ATTRIBUT)+", ConjugSyri.iclasse= "+ConjClasseSyriM.getClasse()+", Conjugueur.M.ConjugSyri.SYS.i2S(contrôleur.model.getSchème()) = "+ Conjugueur.M.Conjug.M.i2M(contrôleur.model.getSchème()) +", contrôleur.model.getTemps() = "+Conjugueur.M.ConjugSyri.T.i2T(contrôleur.model.getTemps()).toString()+", ConjClasseSyriM.getClasse() "+ConjClasseSyriM.getClasse()) ;
        try {
            switch (Conjugueur.M.ConjugSyri.SYT.i2T(contrôleur.model.getTemps())) {                                     // temps
                case Accompli -> {
                    switch (Conjugueur.M.ConjugSyri.SYS.i2S(contrôleur.model.getSchème())) {                                  // schème
                        case Peal -> {                                                 // SIMPLE + ACTIVE = Peal
                            JFrameConjugSyri.jLabelVoix.setText("Voix Active"); JFrameConjugSyri.JLabelForme.setText("Forme simple");
                            if (déclinaisonChildren.isEmpty()){             // verbe régulier
                                if (YUD == new StringBuffer(Conjugueur.M.ConjugSyri.comboBoxVerbeM.get(contrôleur.model.getIndVerbe()).getAttributeValue(Conjugueur.M.ConjugSyri.ATTRIBUT)).toString().toCharArray()[0]){
                                    for (SYP personne : SYP.values()) DéclinerRégulièrement (personne, contrôleur) ;    
                                }                                               // P- yud
                                else for (SYP personne : SYP.values()) DéclinerRégulièrement (personne, contrôleur) ;
                        }                                               // verbe régulier
                        else {                                              // verbe irrégulier
                          CopierIrrégularités ("Peal") ;
                        }                                                   // verbe irrégulier
                      }                                                         // Peal
                      case Etpeel -> {
                          JFrameConjugSyri.jLabelVoix.setText("Voix Passive"); JFrameConjugSyri.JLabelForme.setText("Forme simple");
                            if (déclinaisonChildren.isEmpty()){             // verbe régulier
                                for (SYP personne : SYP.values()) DéclinerRégulièrement (personne, contrôleur) ;
                      }                                               // verbe régulier
                          
                      }                                                               // Etpeel
                      case Pael -> {
                          JFrameConjugSyri.jLabelVoix.setText("Voix Active"); JFrameConjugSyri.JLabelForme.setText("Forme intensive");
                           if (déclinaisonChildren.isEmpty()){             // verbe régulier
                                for (SYP personne : SYP.values()) DéclinerRégulièrement (personne, contrôleur) ;
                            }                                               // verbe régulier
                      }                                                               // Pael
                      case Etpaal-> {
                          JFrameConjugSyri.jLabelVoix.setText("Voix Passive"); JFrameConjugSyri.JLabelForme.setText("Forme intensive");
                           if (déclinaisonChildren.isEmpty()){             // verbe régulier
                                for (SYP personne : SYP.values()) DéclinerRégulièrement (personne, contrôleur) ;
                            }                                               // verbe régulier
                      }                                                               // Etpaal
                      case Aphel-> {
                          JFrameConjugSyri.jLabelVoix.setText("Voix Active"); JFrameConjugSyri.JLabelForme.setText("Forme factative");
                           if (déclinaisonChildren.isEmpty()){             // verbe régulier
                                for (SYP personne : SYP.values()) DéclinerRégulièrement (personne, contrôleur) ;
                            }                                               // verbe régulier
                      }                                                               // Aphel
                      case Ettaphal-> {
                          JFrameConjugSyri.jLabelVoix.setText("Voix Active"); JFrameConjugSyri.JLabelForme.setText("Forme factative");
                           if (déclinaisonChildren.isEmpty()){             // verbe régulier
                                for (SYP personne : SYP.values()) DéclinerRégulièrement (personne, contrôleur) ;
                            }                                               // verbe régulier
                      }                                                               // Ettaphal
                  }                                                           // schème
                  
              }                                                                 // Temps accompli
            case Inaccompli -> {
                switch (Conjugueur.M.ConjugSyri.SYS.i2S(contrôleur.model.getSchème())) {                                  // schème
                    case Peal -> {                                                 // SIMPLE + ACTIVE = Peal
                        JFrameConjugSyri.jLabelVoix.setText("Voix Active"); JFrameConjugSyri.JLabelForme.setText("Forme simple");
                        if (déclinaisonChildren.isEmpty()){             // verbe régulier
                                for (SYP personne : SYP.values()) DéclinerRégulièrement (personne, contrôleur) ;
                      }                                               // verbe régulier
                      else {                                              // verbe irrégulier
                          CopierIrrégularités ("Peal") ;
                      }                                                   // verbe irrégulier
                    }                                                         // Peal
                }                                                             // schème
            }
            case Impératif -> {
                switch (Conjugueur.M.ConjugSyri.SYS.i2S(contrôleur.model.getSchème())) {                                  // schème
                    case Peal -> {                                                 // SIMPLE + ACTIVE = Peal
                        JFrameConjugSyri.jLabelVoix.setText("Voix Active"); JFrameConjugSyri.JLabelForme.setText("Forme simple");
                        if (déclinaisonChildren.isEmpty()){             // verbe régulier
                            DéclinerRégulièrement (SYP.SY2MS, contrôleur) ;
                            DéclinerRégulièrement (SYP.SY2FS, contrôleur) ;
                            DéclinerRégulièrement (SYP.SY2MP, contrôleur) ;
                            DéclinerRégulièrement (SYP.SY2FP, contrôleur) ;
                        }                                               // verbe régulier
                        else {                                              // verbe irrégulier
                          CopierIrrégularités ("Peal") ;
                        }                                                   // verbe irrégulier
                    }                                                         // Peal
                }                                                             // schème
            }                                                                   // Impératif

            case Participe -> {
                switch (Conjugueur.M.ConjugSyri.SYS.i2S(contrôleur.model.getSchème())) {                                  // schème
                    case Peal -> {                                                 // SIMPLE + ACTIVE = Peal
                        JFrameConjugSyri.jLabelVoix.setText("Voix Active"); JFrameConjugSyri.JLabelForme.setText("Forme simple");
                        if (déclinaisonChildren.isEmpty()){             // verbe régulier
                        }                                               // verbe régulier
                        else {                                              // verbe irrégulier
                          CopierIrrégularités ("Peal") ;
                        }                                                   // verbe irrégulier
                    }                                                         // Peal
                }                                                             // schème
            }                                                                   // Temps PARTICIPE

                }                                                               // temps
        } catch (BadLocationException ble) {}
    }                                                                           // updateTextPaneConj
    
    static boolean Consonne (char c) {
//        if (DEBUG) { System.out.println ("ConjugSyri::Consonne, c = "+c) ;   }
      if ((c >= 'ܐ') && (c <= 'ܬ')) return true ; 
      return false ;
    }                                                                            // Consonne

        private void CopierIrrégularités (String schème) throws BadLocationException {
//        if (DEBUG) System.out.println("ConjugSyri::CopierIrrégularités schème = "+ schème+", déclinaisonChildren.size() = "+déclinaisonChildren.size()) ;
        for (int i = 0 ; i < déclinaisonChildren.size(); i++) {                  // Pour ttes les déclinaisons
//            if (DEBUG) System.out.println("ConjugSyri::CopierIrrégularités, déclinaisonChildren.get("+i+").getAttribute(\"temps\").getValue() = " + déclinaisonChildren.get(i).getAttribute("temps").getValue()) ;
            if (   (déclinaisonChildren.get(i).getAttribute("temps").getValue().compareTo(Conjugueur.M.ConjugSyri.T.i2T(contrôleur.model.getTemps()).toString()) == 0)
                && (déclinaisonChildren.get(i).getAttribute("schème").getValue().compareTo(schème) == 0) )  {
                inbLignes = AjouterLigne(SYP.l2P(déclinaisonChildren.get(i).getAttribute("personne").getValue()).ip(), SYP.l2P(déclinaisonChildren.get(i).getAttribute("personne").getValue()).lp(), Conjugueur.V.JFrameConjug.SYRIAC, StyleConstants.ALIGN_RIGHT) ;
                Copier(inbLignes, SYP.l2P(déclinaisonChildren.get(i).getAttribute("personne").getValue()).lhp(), DéclinaisonStyledDoc.stylepp); Espace(inbLignes);
                Copier(inbLignes, déclinaisonChildren.get(i).getText(), DéclinaisonStyledDoc.stylesu);
                AjouterTranslittération(inbLignes, syriacToLatinTrans) ;
            }
        }                                                                       // Pour ttes les déclinaisons
    }                                                                           // CopierIrrégularités
    /**
    * Algorithme
    * 1. Copier le libellé du Pronom Personnel
    * 2. Si le préfixe existe, l'ajouter
    */
    private void DéclinerRégulièrement(SYP personne, Conjugueur.C.Conjug contrôleur) throws BadLocationException {
        if (DEBUG) System.out.println("ConjugSyri::DéclinerRégulièrement, personne = " + personne.lp+", Conjugueur.M.ConjugSyri.SYS.i2S(contrôleur.model.getSchème()) = "+Conjugueur.M.ConjugSyri.SYS.i2S(contrôleur.model.getSchème())) ;
        if (!"0".equals(personne.pairePS[Conjugueur.M.ConjugSyri.SYS.i2S(contrôleur.model.getSchème()).is()][contrôleur.model.getTemps()][ConjClasseSyriM.getClasse().ic()][PRÉFIXE])) {
            inbLignes = AjouterLigne(personne.ip(), personne.lp(), Conjugueur.V.JFrameConjug.SYRIAC, StyleConstants.ALIGN_RIGHT) ; nbcons = 0 ;
            Copier(inbLignes, personne.lhp(), DéclinaisonStyledDoc.stylepp); Espace (inbLignes) ;
            if (!personne.pairePS[Conjugueur.M.ConjugSyri.SYS.i2S(contrôleur.model.getSchème()).is()][contrôleur.model.getTemps()][ConjClasseSyriM.getClasse().ic()][PRÉFIXE].isEmpty()) Préfixer(inbLignes, personne.pairePS[Conjugueur.M.ConjugSyri.SYS.i2S(contrôleur.model.getSchème()).is()][contrôleur.model.getTemps()][ConjClasseSyriM.getClasse().ic()][PRÉFIXE]) ;

            for (char c : Conjugueur.M.ConjugSyri.comboBoxVerbeM.get(contrôleur.model.getIndVerbe()).getAttributeValue(Conjugueur.M.ConjugSyri.ATTRIBUT).toCharArray()){
                if (Consonne(c)) {                                // le caractère courant est une consonne
                    nbcons++ ;
                    Copier (inbLignes, String.valueOf(c), DéclinaisonStyledDoc.stylera) ;
                    Copier (inbLignes, Character.toString(personne.accents [Conjugueur.M.ConjugSyri.SYS.i2S(contrôleur.model.getSchème()).is()][contrôleur.model.getTemps()][ConjClasseSyriM.getClasse().ic()][(short)(nbcons-1)]), DéclinaisonStyledDoc.stylesu) ;
                    if (personne.accents [Conjugueur.M.ConjugSyri.SYS.i2S(contrôleur.model.getSchème()).is()][contrôleur.model.getTemps()][ConjClasseSyriM.getClasse().ic()][(short)(nbcons-1)] == '\u0000') Copier (inbLignes, Character.toString(Conjugueur.M.ConjugSyri.SYS.i2S(contrôleur.model.getSchème()).accents [(short)(nbcons-1)]), DéclinaisonStyledDoc.stylesu) ;
                }                                                 // le caractère courant était une consonne
            }                                                    // pour ts les caractères
            if (!personne.pairePS [Conjugueur.M.ConjugSyri.SYS.i2S(contrôleur.model.getSchème()).is()][contrôleur.model.getTemps()][ConjClasseSyriM.getClasse().ic()][SUFFIXE].isEmpty())  Suffixer (inbLignes, personne.pairePS [Conjugueur.M.ConjugSyri.SYS.i2S(contrôleur.model.getSchème()).is()][contrôleur.model.getTemps()][ConjClasseSyriM.getClasse().ic()][SUFFIXE]) ;
            AjouterTranslittération(inbLignes, syriacToLatinTrans) ;
        }
     } 

