    /** Constructeur de l'enum
     * @param ip indice de personne 0, 1, 2, 3...
     * @param libpers libellé de personne 1è. s., 2è. m. s., 2è. f. s., 3è. m. s....
     * @param accents accents sur les 1ère, 2ème et 3ème consonne
     * @param pairePS tableau 1ère dim : schème, 2ème dim : préfixe et suffixe
     */
        SYP(short ip, String libpers, String lhp, char [][][][] accents, String [][][][] pairePS) {
            this.ip = ip ; this.lp = libpers ; this.lhp    = lhp ; this.accents = accents ; this.pairePS = pairePS ;    }
